const today = new Date().toISOString().slice(0, 10);
const FEISHU_WEBHOOK = $env.FEISHU_WEBHOOK || 'https://open.feishu.cn/open-apis/bot/v2/hook/YOUR_WEBHOOK_TOKEN';
return [{ json: { date: today, feishuWebhook: FEISHU_WEBHOOK } }];

// TechCrunch 解析 - RSS格式
const resp = $input.first().json;
const status = resp.statusCode || 0;
const body = resp.data || resp.body || '';

if (status !== 200 || !body || body.length < 100) {
    return [{ json: { source: 'TechCrunch', items: [], error: `HTTP ${status}`, detail: '请求失败' } }];
}

const items = [];
const itemRegex = /<item[\s>]*([\s\S]*?)<\/item>/gi;
let match;
let count = 0;

while ((match = itemRegex.exec(body)) !== null && count < 10) {
    const xml = match[1];

    // 提取标题
    let title = '';
    const titleMatch = xml.match(/<title>([\s\S]*?)<\/title>/i);
    if (titleMatch) {
        title = titleMatch[1].replace(/<\!\[CDATA\[([\s\S]*?)\]\]>/, '$1').trim();
    }

    // 提取链接
    let link = '';
    const linkMatch = xml.match(/<link>(.*?)<\/link>/i);
    if (linkMatch) link = linkMatch[1].trim();

    // 提取描述
    let desc = '';
    const descMatch = xml.match(/<description>([\s\S]*?)<\/description>/i);
    if (descMatch) {
        desc = descMatch[1].replace(/<\!\[CDATA\[([\s\S]*?)\]\]>/, '$1');
        desc = desc.replace(/<[^>]+>/g, ' ').replace(/&[a-z]+;/g, ' ').substring(0, 200).trim();
    }

    // 提取日期
    let date = '';
    const dateMatch = xml.match(/<pubDate>(.*?)<\/pubDate>/i);
    if (dateMatch) date = dateMatch[1].trim();

    // 提取作者
    let author = '';
    const creatorMatch = xml.match(/<dc:creator>([\s\S]*?)<\/dc:creator>/i);
    if (creatorMatch) {
        author = creatorMatch[1].replace(/<\!\[CDATA\[([\s\S]*?)\]\]>/, '$1').trim();
    }

    if (title) {
        items.push({ title, link, description: desc, date, author });
        count++;
    }
}

return [{ json: { source: 'TechCrunch', items, count: items.length } }];

// HackerNews 解析 - RSS格式
const resp = $input.first().json;
const status = resp.statusCode || 0;
const body = resp.data || resp.body || '';

if (status !== 200 || !body || body.length < 100) {
    return [{ json: { source: 'HackerNews', items: [], error: `HTTP ${status}`, detail: '请求失败' } }];
}

const items = [];
const itemRegex = /<item[\s>]*([\s\S]*?)<\/item>/gi;
let match;
let count = 0;

while ((match = itemRegex.exec(body)) !== null && count < 10) {
    const xml = match[1];

    let title = '';
    const titleMatch = xml.match(/<title>([\s\S]*?)<\/title>/i);
    if (titleMatch) {
        title = titleMatch[1].replace(/<\!\[CDATA\[([\s\S]*?)\]\]>/, '$1').trim();
    }

    let link = '';
    const linkMatch = xml.match(/<link>(.*?)<\/link>/i);
    if (linkMatch) link = linkMatch[1].trim();

    let desc = '';
    const descMatch = xml.match(/<description>([\s\S]*?)<\/description>/i);
    if (descMatch) {
        desc = descMatch[1].replace(/<\!\[CDATA\[([\s\S]*?)\]\]>/, '$1');
        desc = desc.replace(/<[^>]+>/g, ' ').replace(/&[a-z]+;/g, ' ').substring(0, 200).trim();
    }

