    if (dateMatch) date = dateMatch[1].trim();

    // 提取Points
    let points = 0;
    const pointsMatch = desc.match(/Points:\s*(\d+)/);
    if (pointsMatch) points = parseInt(pointsMatch[1]);

    if (title) {
        items.push({ title, link, description: desc, date, points });
        count++;
    }
}

