// ProductHunt 解析 - Atom格式
const resp = $input.first().json;
const status = resp.statusCode || 0;
const body = resp.data || resp.body || '';

if (status !== 200 || !body || body.length < 100) {
    return [{ json: { source: 'ProductHunt', items: [], error: `HTTP ${status}`, detail: '请求失败' } }];
}

const items = [];
const entryRegex = /<entry[\s>]*([\s\S]*?)<\/entry>/gi;
let match;
let count = 0;

while ((match = entryRegex.exec(body)) !== null && count < 10) {
    const xml = match[1];

    // 提取标题 (纯文本，无CDATA)
    let title = '';
    const titleMatch = xml.match(/<title>([\s\S]*?)<\/title>/i);
    if (titleMatch) {
        title = titleMatch[1].trim();
    }

    // 提取链接 - 在href属性里！
    let link = '';
    const linkMatch = xml.match(/<link[^>]*rel="alternate"[^>]*href="([^"]+)"/i);
    if (linkMatch) {
        link = linkMatch[1];
    }

    // 提取描述 - 在content标签里，HTML实体编码
    let desc = '';
    const contentMatch = xml.match(/<content[^>]*>([\s\S]*?)<\/content>/i);
    if (contentMatch) {
        desc = contentMatch[1];
        // 解码HTML实体
        desc = desc.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&');
        // 提取第一个p标签内容
        const pMatch = desc.match(/<p>(.*?)<\/p>/i);
        if (pMatch) {
            desc = pMatch[1].trim();
        } else {
            desc = desc.replace(/<[^>]+>/g, ' ').substring(0, 200).trim();
        }
    }

    if (title) {
        items.push({ title, link, description: desc });
        count++;
    }
}

return [{ json: { source: 'ProductHunt', items, count: items.length } }];

// 格式化日报 - 飞书卡片兼容格式
const allData = $input.all().map(i => i.json);
const config = $('初始化配置').first().json;
const date = config.date;

const sources = [
  { key: 'TechCrunch',   icon: '🐦', label: 'TechCrunch 热门' },
  { key: 'HackerNews',   icon: '🔶', label: 'HackerNews 热门' },
  { key: 'ProductHunt',  icon: '🚀', label: 'Product Hunt 今日新品' }
];

const dataMap = new Map();
for (const d of allData) dataMap.set(d.source, d);

const results = sources.map(s => {
  const raw = dataMap.get(s.key) || { items: [], error: null, detail: null };
  return { ...s, ...raw };
});

const totalItems = results.reduce((sum, r) => sum + (r.items?.length || 0), 0);
const errors = results
  .filter(r => r.error)
  .map(r => ({ source: r.key, msg: r.error, detail: r.detail }));

const now = new Date();
const beijingTime = new Date(now.getTime() + 8 * 60 * 60 * 1000);
const timeStr = beijingTime.toISOString().replace('T', ' ').slice(0, 19) + ' (北京时间)';

const okCount = results.length - errors.length;
let md = '';

if (okCount === results.length) {
  md += `**✅ 所有数据源获取成功** | 📊 总文章数: ${totalItems} 条\n\n`;
} else {
  md += `**⚠️ 数据获取状态**\n`;
  md += `✅ 成功: ${okCount}/${results.length} 个数据源\n`;
  md += `❌ 失败: ${errors.length}/${results.length} 个数据源\n`;
  md += `📊 总文章数: ${totalItems} 条\n\n`;
  md += `**错误详情:**\n`;
  errors.forEach(e => {
    md += `- **${e.source}**: ${e.msg}${e.detail ? '\n  > ' + e.detail : ''}\n`;
  });
  md += '\n';
}

results.forEach(r => {
  md += `---\n`;
  md += `**${r.icon} ${r.label}**`;
  if (r.error) {
    md += ` ❌ ${r.error}\n\n`;
    return;
  }
  const count = r.items?.length || 0;
  md += ` (${count}条)\n`;
  if (count === 0) {
    md += `> 本时段暂无数据\n\n`;
    return;
  }
  (r.items || []).forEach((item, i) => {
    const title = item.title || '(无标题)';
    const desc = item.description ? ` — ${String(item.description).substring(0, 120)}` : '';
    const score = r.key === 'HackerNews' && item.points ? ` (${item.points}分)` : '';
    const link = item.link ? ` [🔗查看详情](${item.link})` : '';
    md += `${i + 1}. **${title}**${score}${desc}${link}\n`;
  });
  md += '\n';
});

md += `---\n*由 n8n 自动生成 | ${timeStr}*`;

return [{ 
  json: { 
    markdown: md, 
    date, 
    totalItems, 
    errorCount: errors.length, 
    errors, 
    feishuWebhook: config.feishuWebhook 
  } 
}];

const data = $input.first().json;
const md = data.markdown || '';
const truncated = md.length > 8000 ? md.substring(0, 7900) + '\n\n... (内容已截断)' : md;

const title = data.errorCount > 0
  ? `📊 科技资讯日报 (⚠️ ${data.errorCount}个源失败)`
  : '📊 科技资讯日报';
const template = data.errorCount > 0 ? 'red' : 'blue';

const payload = {
  msg_type: "interactive",
  card: {
    schema: "2.0",
    config: { wide_screen_mode: true },
    header: {
      title: { tag: "plain_text", content: `${title} ${data.date}` },
      template: template
    },
    body: {
      elements: [
        { tag: "markdown", content: truncated }
      ]
    }
  }
};

return [{
  json: {
    webhookUrl: data.feishuWebhook,
    payload: payload,
    date: data.date,
    totalItems: data.totalItems,
    errorCount: data.errorCount
  }
}];

// 从初始化配置获取日期
const initConfig = $('初始化配置').first().json;
const date = initConfig?.date || '未知日期';

// 从格式化日报获取统计
const formatData = $('格式化日报').first().json;
const totalItems = formatData?.totalItems || 0;
const errorCount = formatData?.errorCount || 0;

// 从当前输入获取飞书响应
const feishuResp = $input.first().json;
let feishuStatus = '未执行';
if (feishuResp) {
    const code = feishuResp.code ?? feishuResp.StatusCode;
    if (code === 0) feishuStatus = '✅ 发送成功';
    else if (code !== undefined) feishuStatus = `❌ API错误: ${code}`;
    else if (feishuResp.statusCode) feishuStatus = feishuResp.statusCode === 200 ? '✅ 发送成功' : `❌ HTTP错误: ${feishuResp.statusCode}`;
}

return [{ json: { message: `✅ 日报生成完成: ${date}`, totalItems, errors: errorCount > 0 ? `${errorCount}个数据源失败` : '无', feishuStatus } }];

const allData = $input.all().map(i => i.json);

// ========== 数据清洗 ==========
function cleanText(str) {
  if (!str || typeof str !== 'string') return '';
  return str
    .replace(/https?:\/\/[^\s]+/g, '')      // 去URL（最先）
    .replace(/<[^>]+>/g, '')                // 去HTML标签
    .replace(/&\w+;/g, '')                  // 去HTML实体
    .replace(/\n/g, ' ')                    // 换行转空格
    .replace(/\s+/g, ' ')                   // 合并空格
    .trim();
}

function isRealEnglish(text) {
  if (!text || text.length < 5) return false;
  const letters = (text.match(/[a-zA-Z]/g) || []).length;
  const total = text.replace(/\s/g, '').length;
  return total > 0 && letters > 10 && (letters / total) > 0.6;
}

// ========== 收集待翻译文本 ==========
const textsToTranslate = [];
const textMap = [];

for (let sIdx = 0; sIdx < allData.length; sIdx++) {
  const source = allData[sIdx];
  if (!source?.items) continue;

  for (let iIdx = 0; iIdx < source.items.length; iIdx++) {
    const item = source.items[iIdx];

    // title
    const cleanTitle = cleanText(item.title);
    if (isRealEnglish(cleanTitle)) {
      textsToTranslate.push(cleanTitle.substring(0, 300));
      textMap.push({ sIdx, iIdx, field: 'title', original: cleanTitle });
    }

    // description
    const cleanDesc = cleanText(item.description);
    if (isRealEnglish(cleanDesc)) {
      const descShort = cleanDesc.substring(0, 100);
      textsToTranslate.push(descShort);
      textMap.push({ sIdx, iIdx, field: 'description', original: descShort, fullDesc: cleanDesc });
    }
  }
}

// ========== 去重 ==========
const uniqueTexts = [...new Set(textsToTranslate)];
console.log(`需翻译: ${uniqueTexts.length} 条, 对应位置: ${textMap.length} 个`);

// ========== 分批翻译 ==========
const batchSize = 30;
const batches = [];
for (let i = 0; i < uniqueTexts.length; i += batchSize) {
  batches.push(uniqueTexts.slice(i, i + batchSize));
}

console.log(`分 ${batches.length} 批，每批 ${batchSize} 条`);

const translatedMap = {};

for (let i = 0; i < batches.length; i++) {
  const batch = batches[i];
  console.log(`执行批次 ${i + 1}/${batches.length}，${batch.length} 条...`);

  const prompt = `将以下${batch.length}个英文翻译成中文。规则：
1. 标题：简洁有力，20字内，保留产品名
2. 描述：通顺易懂，80字内
3. 每行一个翻译结果，不要编号，不要解释，不要引号

待翻译：
${batch.map((t, idx) => `${idx + 1}. ${t}`).join('\n')}

翻译结果：`;

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `http://${$env.OLLAMA_HOST || 'localhost'}:${$env.OLLAMA_PORT || '11434'}/v1/chat/completions`,
      headers: { 'Content-Type': 'application/json' },
      body: {
        // model: 'qwen3:0.6b',
        // model: 'qwen3:1.7b',
        model: 'qwen2.5:3b',
        messages: [
          { role: 'system', content: '你是科技资讯翻译助手。' },
          { role: 'user', content: prompt }
        ],
        temperature: 0.1,
        max_tokens: 2000,
        stream: false
      },
      timeout: 720000
    });

    const content = response.choices?.[0]?.message?.content || '';
    console.log(`批次 ${i + 1} 返回长度: ${content.length}`);

    // 解析
    const lines = content.split('\n')
      .map(l => l.replace(/^\d+[\.\s]+/, '').trim())
      .filter(l => l.length > 0 && !l.includes('待翻译') && !l.includes('翻译结果') && !l.includes('规则'));

    console.log(`批次 ${i + 1} 解析出 ${lines.length} 行`);

    // 回填（严格按索引，数量不对时取最小）
    const matchCount = Math.min(batch.length, lines.length);
    for (let j = 0; j < matchCount; j++) {
      if (lines[j] && lines[j] !== batch[j]) {
        translatedMap[batch[j]] = lines[j];
      }
    }

    if (matchCount < batch.length) {
      for (let j = matchCount; j < batch.length; j++) {
        console.log(`未匹配[${j}]: ${batch[j].substring(0, 50)}`);
      }
    }

    console.log(`批次 ${i + 1} 成功: ${matchCount}/${batch.length}`);

  } catch (e) {
    console.log(`批次 ${i + 1} 错误: ${e.message}`);
  }
}

// ========== 回填到原JSON ==========
let translatedCount = 0;
textMap.forEach(pos => {
  const translated = translatedMap[pos.original];
  if (translated) {
    translatedCount++;
    if (pos.field === 'title') {
      allData[pos.sIdx].items[pos.iIdx].title = translated;
    } else {
      const ratio = translated.length / pos.original.length;
      const targetLen = Math.min(Math.floor(pos.fullDesc.length * ratio * 1.2), 180);
      allData[pos.sIdx].items[pos.iIdx].description = translated.substring(0, targetLen) + (targetLen < translated.length ? '...' : '');
    }
  }
});

console.log(`最终回填: ${translatedCount}/${textMap.length}`);

return allData.map(source => ({ json: source }));
